import { useContext, useState } from "react";
import { ThemeContext } from "../context/ThemeContext";

export default function TopBar({ user, setUser }) {
    const { theme, toggleTheme } = useContext(ThemeContext);
    const [menuOpen, setMenuOpen] = useState(false);
    const [showLogin, setShowLogin] = useState(false);
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    // LOGIN HANDLER
    const handleLogin = async (e) => {
        e.preventDefault();
        try {
            const res = await fetch("http://127.0.0.1:8000/api/login", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, password })
            });

            if (!res.ok) throw new Error("Invalid credentials");

            const data = await res.json(); // { user: {...}, token: "..." }

            localStorage.setItem("token", data.token);
            setUser(data.user);
            setShowLogin(false);
        } catch (err) {
            alert(err.message);
        }
    };

    // LOGOUT HANDLER
    const handleLogout = () => {
        setUser(null);
        localStorage.removeItem("token");
        setMenuOpen(false);
    };

    return (
        <header className="topbar">
            <div className="topbar-left">
                <h1 className="title">Vyom's AI Chatbot</h1>
            </div>

            <div className="topbar-right">
                <button className="icon" onClick={toggleTheme}>
                    {theme === "dark" ? "☀️" : "🌙"}
                </button>

                {!user ? (
                    <button className="login" onClick={() => setShowLogin(true)}>
                        Login
                    </button>
                ) : (
                    <div
                        className="user-wrapper"
                        onMouseEnter={() => setMenuOpen(true)}
                        onMouseLeave={() => setMenuOpen(false)}
                    >
                        <div className="user-info">
                            <div className="avatar">👤</div>
                            <span className="username">{user.name}</span>
                            <svg width="10" height="10" viewBox="0 0 24 24" className="caret-icon">
                                <path d="M6 9L12 15L18 9" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                            </svg>
                        </div>

                        {menuOpen && (
                            <div className="dropdown">
                                <button onClick={handleLogout}>Logout</button>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* LOGIN MODAL */}
            {showLogin && (
                <div className="login-modal-backdrop">
                    <div className="login-modal">
                        <h3>Login</h3>
                        <form onSubmit={handleLogin}>
                            <input
                                type="email"
                                placeholder="Email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                            />
                            <input
                                type="password"
                                placeholder="Password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />
                            <button type="submit">Login</button>
                        </form>
                        <button onClick={() => setShowLogin(false)} style={{ marginTop: '10px', background: '#ccc', color: '#000' }}>
                            Cancel
                        </button>
                    </div>
                </div>
            )}
        </header>
    );
}
